local Moons = require("Module:Moons");
local I18n = require("Module:I18n");

return {
	["main"] = function(frame)
		local version = frame.args["version"] or "latest";
		local lang = frame.args["lang"] or mw.message.getDefaultLanguage().code;
		local interiorIndex = tonumber(frame.args[1]);
		local interiorNameEn = ({ [1] = "Factory", [2] = "Mansion", [5] = "Mineshaft" })[interiorIndex];
		local data = {};
		for _, v in pairs(Moons.getData()) do
			local moonDispNames = Moons.MOON_ALIASES[v.mName];
			local weightSum = 0;
			for _, weight in pairs(v.dungeonRarities or {}) do weightSum = weightSum + weight; end
			table.insert(data, {
				mName = v.mName,
				dispNameEn = moonDispNames[#moonDispNames], -- last is full name w/o num, which the page names follow
				moonKeyIndex = Moons.getMoonKeyIndex(v.mName),
				dungeonRarities = v.dungeonRarities, -- pass through nil, don't provide default
				dungeonRaritiesTotal = weightSum;
			});
		end
		table.sort(data, function(a, b) return a.moonKeyIndex < b.moonKeyIndex; end);
		local contents = (frame:expandTemplate{ title = "AutoSingleInteriorRarities_preface", args = { I18n.getTranslation(lang, interiorNameEn, "InteriorTypes") } }).."\n";
		for _, moon in pairs(data) do
			if moon.dungeonRarities and (not Moons.omitLiquidation or moon.mName ~= "LiquidationLevel") then
				local nameStr = I18n.getLocalizedPageLink(moon.dispNameEn, lang);
				local weight = moon.dungeonRarities[interiorIndex] or 0;
				local chanceStr = weight == 0 and "style=\"opacity: 0.5;\" | <i>0%</i>" or ("%.2f%%"):format(weight * 100 / moon.dungeonRaritiesTotal);
				contents = contents.."|-\n| "..nameStr.." || "..chanceStr.."\n";
			end
		end
		return contents.."|}";
	end,
};
